<h2 style="margin-bottom:20px">Modifier la relation Post / Tag</h2><form action="/admin/post-tags/update"method="post"style="background:#fff;padding:20px;border-radius:8px;box-shadow:0 2px 8px rgba(0,0,0,.1);max-width:700px"><input name="old_post_id"type="hidden"value="<?=(int)$relation['post_id']?>"> <input name="old_tag_id"type="hidden"value="<?=(int)$relation['tag_id']?>"> <label>Article</label><br><select name="post_id"required style="width:100%;padding:10px;margin:8px 0 14px"><?php foreach($posts as $post): ?><option value="<?=(int)$post['id']?>"<?=(int)$post['id']===(int)$relation['post_id']?'selected':''?>>#<?=(int)$post['id']?>-<?=htmlspecialchars($post['title'])?></option><?php endforeach; ?></select><br><label>Tag</label><br><select name="tag_id"required style="width:100%;padding:10px;margin:8px 0 14px"><?php foreach($tags as $tag): ?><option value="<?=(int)$tag['id']?>"<?=(int)$tag['id']===(int)$relation['tag_id']?'selected':''?>>#<?=(int)$tag['id']?>-<?=htmlspecialchars($tag['name'])?></option><?php endforeach; ?></select><br><button style="padding:10px 16px;background:#667eea;color:#fff;border:0;border-radius:5px"type="submit">Mettre à jour</button> <a href="/admin/post-tags"style="margin-left:10px">Annuler</a></form>